const booking = $input.first().json;
const responses = booking.responses || {};
const name = responses.name || booking.attendees?.[0]?.name || 'Unknown';
const email = responses.email || booking.attendees?.[0]?.email || '';
const phone = responses.phone || booking.attendees?.[0]?.phoneNumber || '';
const eventTypeMap = {
  'studio-clean': 'studio',
  '1-bedroom-clean': '1_bed',
  '2-bedroom-clean': '2_bed',
  '3-bedroom-clean': '3_bed',
  '4-bedroom-clean': '4_plus_bed',
  'commercial-clean': 'commercial',
  'turnover-clean': '2_bed'
};
const calEventType = booking.eventType?.slug || 'turnover-clean';
const propertyType = eventTypeMap[calEventType] || '2_bed';
const address = responses.address || booking.description || 'TBD';
const accessCode = responses['access-code'] || null;
const unitName = responses['unit-name'] || null;
const specialRequests = responses.notes || null;
return {
  json: {
    calcom_uid: booking.uid,
    client: { name, email, phone },
    service: {
      type: 'turnover_clean',
      duration_minutes: booking.duration || 120,
      scheduled_at: booking.startTime
    },
    property: {
      type: propertyType,
      address,
      access_code: accessCode,
      unit_name: unitName,
      special_requests: specialRequests
    }
  }
};

const response = $input.first().json;
if (response.status === 'scheduled') {
  return { json: { action: 'send_confirmation', job_id: response.job_id } };
}
if (response.status === 'duplicate') {
  return { json: { action: 'skip', reason: 'duplicate' } };
}
return { json: { action: 'alert_admin', error: response.error } };
